-- ── 2. public.users (direct insert — no trigger needed) ──────
ON CONFLICT (id) DO UPDATE SET email = EXCLUDED.email;

-- ── 3. public.profiles (direct insert with full data) ────────
ON CONFLICT (user_id) DO UPDATE SET
  first_name=EXCLUDED.first_name, last_name=EXCLUDED.last_name,
  employer_name=EXCLUDED.employer_name, gross_income_eur=EXCLUDED.gross_income_eur,
  profile_complete=EXCLUDED.profile_complete, updated_at=now();

-- ── 4. public.applications (50 applications, varied statuses) ─
ON CONFLICT (user_id, tax_year) DO UPDATE SET
  status=EXCLUDED.status, payment_status=EXCLUDED.payment_status, updated_at=now();

-- ── Verify counts ─────────────────────────────────────────────
SELECT 'auth.users'           AS tbl, count(*) FROM auth.users        WHERE id::text LIKE '11111111%'
UNION ALL
SELECT 'public.users'         AS tbl, count(*) FROM public.users       WHERE id::text LIKE '11111111%'
UNION ALL
SELECT 'public.profiles'      AS tbl, count(*) FROM public.profiles    WHERE user_id::text LIKE '11111111%'
UNION ALL
SELECT 'public.applications'  AS tbl, count(*) FROM public.applications WHERE user_id::text LIKE '11111111%';

